INSERT INTO tenant_leases (application_id, start_date, end_date, monthly_rent, lease_type, duration, signed_at)
SELECT a.id, '2026-05-01'::date,
  (CASE WHEN a.retailer_display_id='PTG-APP-2026-9104' THEN '2026-06-27' ELSE '2027-04-30' END)::date,
  su.price_thb, 'Standard Retail', '12 months', now()
FROM applications a JOIN station_units su ON su.id=a.station_unit_id
WHERE a.retailer_display_id IN ('PTG-APP-2026-8080','PTG-APP-2026-9101','PTG-APP-2026-9102','PTG-APP-2026-9103','PTG-APP-2026-9104','PTG-APP-2026-9106','PTG-APP-2026-9108');
